import{_ as t,o as i,c as n,a2 as a}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Chapter 16: Testing Coding Agents","description":"Master the unique testing challenges of non-deterministic LLM-powered systems, from mocking model responses to benchmark-driven evaluation.","frontmatter":{"title":"Chapter 16: Testing Coding Agents","description":"Master the unique testing challenges of non-deterministic LLM-powered systems, from mocking model responses to benchmark-driven evaluation."},"headers":[],"relativePath":"learn/linear/16-testing-coding-agents/index.md","filePath":"learn/linear/16-testing-coding-agents/index.md"}'),s={name:"learn/linear/16-testing-coding-agents/index.md"};function r(o,e,l,g,h,c){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="testing-coding-agents" tabindex="-1">Testing Coding Agents <a class="header-anchor" href="#testing-coding-agents" aria-label="Permalink to &quot;Testing Coding Agents&quot;">​</a></h1><p>Testing a coding agent is fundamentally harder than testing a traditional application. The core of your system — the LLM — is non-deterministic, expensive to call, and changes behavior when the provider updates their model. A test that passes today may fail tomorrow, not because your code changed, but because the model responded slightly differently. This chapter equips you with the techniques and mindset needed to build a robust test suite despite this uncertainty.</p><p>We start with the testing philosophy specific to agent systems: what to test deterministically, what to test probabilistically, and what to test by recording real interactions. You will learn how to unit test tools in isolation, mock LLM responses for fast iteration, and integration test the full agentic loop. We cover snapshot testing for catching regressions in tool output, property-based testing for validating invariants across random inputs, and recording/replay for capturing real model interactions as reusable test fixtures.</p><p>The chapter also addresses benchmark testing (evaluating agent performance on standardized tasks), testing your safety systems under adversarial conditions, and setting up CI/CD pipelines that balance test coverage with API cost. By the end, you will have a comprehensive testing strategy that gives you confidence in your agent&#39;s correctness without breaking the bank on API calls.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Develop a testing philosophy that accounts for the non-deterministic nature of LLM-powered systems</li><li>Write effective unit tests for tools, parsers, and other deterministic agent components</li><li>Mock LLM responses to enable fast, repeatable integration tests of the agentic loop</li><li>Implement recording and replay infrastructure for capturing real model interactions as test fixtures</li><li>Apply property-based testing to validate agent invariants across diverse inputs</li><li>Set up CI/CD pipelines that run the right tests at the right time to balance coverage and cost</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/16-testing-coding-agents/01-testing-philosophy.html">Testing Philosophy</a></li><li><a href="/linear/16-testing-coding-agents/02-unit-testing-tools.html">Unit Testing Tools</a></li><li><a href="/linear/16-testing-coding-agents/03-mocking-llm-responses.html">Mocking LLM Responses</a></li><li><a href="/linear/16-testing-coding-agents/04-integration-testing-the-loop.html">Integration Testing the Loop</a></li><li><a href="/linear/16-testing-coding-agents/05-snapshot-testing.html">Snapshot Testing</a></li><li><a href="/linear/16-testing-coding-agents/06-property-based-testing.html">Property Based Testing</a></li><li><a href="/linear/16-testing-coding-agents/07-recording-and-replay.html">Recording and Replay</a></li><li><a href="/linear/16-testing-coding-agents/08-benchmark-testing.html">Benchmark Testing</a></li><li><a href="/linear/16-testing-coding-agents/09-testing-safety-systems.html">Testing Safety Systems</a></li><li><a href="/linear/16-testing-coding-agents/10-ci-cd-for-agents.html">CI CD for Agents</a></li><li><a href="/linear/16-testing-coding-agents/11-test-fixtures.html">Test Fixtures</a></li><li><a href="/linear/16-testing-coding-agents/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 4 (the agentic loop that you will be testing)</li><li>Chapter 5 (the tool system that you will be testing)</li></ul>',10)])])}const u=t(s,[["render",r]]);export{p as __pageData,u as default};
